21	export async function fetchResilient(url, init, { tries = 40, waitMs = 3000 } = {}) {
22	  for (let attempt = 0; ; attempt++) {
23	    try {
24	      return await fetch(url, init);
25	    } catch (e) {
26	      const msg = `${e?.message ?? e} ${e?.cause?.code ?? ''} ${e?.cause?.message ?? ''}`;
27	      if (!TRANSIENT.test(msg) || attempt >= tries) throw e;
28	      await new Promise((r) => setTimeout(r, waitMs));
29	    }
30	  }
