59	  /** Create the session. Init is async pod-side — `send()` waits it out. */
60	  async start({ resumeSessionId, budget, spaceRef = this.spaceRef } = {}) {
61	    const body = {
62	      projectId: this.projectId,
63	      agentSlug: this.agentSlug,
64	      // Bind the session to a PROJECT SPACE's own agent (`<space>/<agent>`) instead of THING
65	      // (session-manager `_initProjectSession` → `parseSpaceRef`). This is what lets a scenario
66	      // probe one specialist's real capability profile directly, rather than inferring it from
67	      // what THING chose to delegate.
68	      ...(spaceRef ? { spaceRef } : {}),
69	      ...(resumeSessionId ? { resumeSessionId } : {}),
70	      ...(budget ? { budget } : {}),
71	    };
72	    const { sessionId } = await this.pod.req('POST', '/api/sessions', body);
73	    this.sessionId = sessionId;
74	    this.log('session', sessionId);
75	    return sessionId;
76	  }
77	
78	  /** Resume an existing session id (post-restart auto-resume scenario). */
79	  async resume(sessionId) {
80	    return this.start({ resumeSessionId: sessionId });
81	  }
82	
83	  /**
84	   * Fast-forward past a RESUMED session's existing trace without attributing it to the next turn.
85	   *
86	   * A scenario that runs Act-by-Act (`--acts=`) resumes the same session from a FRESH process, where
87	   * `lastSeq` starts at 0 — so the first `pullEvents()` replays the WHOLE session history and
88	   * `turn(startSeq)` folds it into the first turn's slice. Any assertion over that slice then reads
89	   * *earlier Acts'* displays: scenario 10 saw a restraint check "pass" on a build summary printed
90	   * two Acts ago. Call this right after `start()`/`resume()` so a turn's events are only its own.
91	   */
92	  async syncToTail() {
93	    for (let i = 0; i < 30; i++) {
94	      const before = this.lastSeq;
95	      await this.pullEvents();
96	      if (this.lastSeq === before) break;
97	      await sleep(200);
98	    }
99	    this.events.length = 0; // replayed history is not the next turn's work
100	    return this.lastSeq;
101	  }
102	
103	  /**
104	   * Pull new trace events since `lastSeq`.
105	   *
106	   * A long turn can spawn many delegate/headless sub-sessions; on a small pod (`maxSessions`) the
107	   * session manager may EVICT this top-level session shortly after its turn completes, so a poll
108	   * then 404s ("unknown session"). That is not a turn failure — the work already landed (assert it
109	   * on real pod state). So a 404 is surfaced as a soft signal (`this.sessionGone = true`) rather
110	   * than thrown; the settle loop treats it as turn-end once work has been seen.
111	   */
112	  async pullEvents() {
113	    let res;
114	    try {
115	      res = await this.pod.req('GET', `/api/sessions/${this.sessionId}/events?since=${this.lastSeq}&format=json`);
116	    } catch (err) {
117	      if (err?.status === 404) {
118	        this.sessionGone = true;
119	        return [];
120	      }
121	      throw err;
122	    }
123	    const { events, lastSeq } = res;
124	    for (const e of events ?? []) {
125	      this.events.push(e.event);
126	      if (this.verbose) this.#logEvent(e.event);
127	    }
128	    if (typeof lastSeq === 'number') this.lastSeq = lastSeq;
129	    return events ?? [];
130	  }
131	
132	  #logEvent(ev) {
133	    switch (ev.type) {
134	      case 'yield':
135	        this.log(`  yield ${ev.kind}`, JSON.stringify(ev.args)?.slice(0, 140));
136	        break;
137	      case 'display':
138	        this.log('  display', JSON.stringify(ev.descriptor)?.slice(0, 200));
139	        break;
140	      case 'node_start':
141	        this.log(`  node_start ${ev.kind} ${ev.label}`);
142	        break;
143	      case 'node_end':
144	        this.log(`  node_end ${ev.nodeId} ${ev.status} ${ev.durationMs}ms`);
145	        break;
146	      case 'eval_error':
147	      case 'typecheck_error':
148	        this.log(`  !! ${ev.type}: ${ev.message?.slice(0, 200)}`);
149	        break;
150	      default:
151	        break;
152	    }
153	  }
154	
155	  /** Open asks, with the raw descriptor (a ConsentCard is `descriptor.type === 'ConsentCard'`). */
156	  async openAsks() {
157	    const { asks } = await this.pod.req('GET', `/api/sessions/${this.sessionId}/asks?format=json`);
158	    return asks ?? [];
159	  }
160	
161	  /**
162	   * Answer an ask. Consent approval is anything in {true, 'approve', {approved:true},
163	   * {approve:true}} (core/src/globals/consent.ts `isConsentApproval`); ANYTHING else — including
164	   * null — is a denial.
165	   */
166	  async answerAsk(askId, value) {
167	    await this.pod.req('POST', `/api/sessions/${this.sessionId}/ask/${askId}`, { value });
168	    this.log('answered ask', askId, JSON.stringify(value));
169	  }
170	
171	  /**
172	   * Send a user message and wait for the turn to settle.
173	   *
174	   * "Settled" = the session is idle AND the trace has stopped growing for `quietMs`. We can't
175	   * key on a single `turn_end` because delegates/forks emit their own in sub-contexts; the
176	   * idle+quiet pair is the only reliable edge over HTTP.
177	   *
178	   * While waiting we drain asks through `onAsk` — that is how consent cards get approved mid-turn.
179	   * A turn blocked on an unanswered ask never goes idle, so an un-handled consent card surfaces as
180	   * a timeout with the ask still open (which the scenario can assert on).
181	   */
182	  /**
183	   * Ensure `this.sessionId` still exists; if it was evicted (`maxSessions` on a small pod), start a
184	   * fresh session — resuming the old id when the pod still has its snapshot, else a clean new one.
185	   * The project (its spaces, app, db) persists on disk regardless, so a re-established session still
186	   * sees everything built so far; only in-VM conversation memory is lost (acceptable — the scenario
187	   * drives self-contained follow-ups).
188	   */
189	  async #ensureAlive() {
190	    if (!this.sessionId) return;
191	    const list = await this.pod.req('GET', '/api/sessions').catch(() => ({ sessions: [] }));
192	    const alive = (list.sessions ?? []).some((s) => s.sessionId === this.sessionId);
193	    if (alive) return;
194	    this.log('session evicted — re-establishing');
195	    const prev = this.sessionId;
196	    try {
197	      await this.start({ resumeSessionId: prev });
198	    } catch {
199	      await this.start();
200	    }
201	    // The re-established session replays its whole persisted trace from seq 0. We ALREADY hold those
202	    // events, so appending the replay duplicates every past turn — and, worse, `turn(startSeq)` then
203	    // slices a window full of REPLAYED history and asserts on it as if it were the turn we just sent
204	    // (scenario 10 read a re-analysis of turn 1's images as the work of its "yes" turn). Drain the
205	    // replay to re-sync `lastSeq`, then discard it: it is history we already have.
206	    const held = this.events.length;
207	    this.lastSeq = 0;
208	    for (let i = 0; i < 30; i++) {
209	      const before = this.lastSeq;
210	      await this.pullEvents();
211	      if (this.lastSeq === before) break;
212	      await sleep(200);
213	    }
214	    this.events.length = held;
215	    this.sessionGone = false;
216	  }
217	
218	  async send(content, opts = {}) {
219	    await this.#ensureAlive();
220	    return this.#dispatchAndWait(
221	      () => this.pod.req('POST', `/api/sessions/${this.sessionId}/message`, { content }),
222	      content,
223	      opts,
224	    );
225	  }
226	
227	  /**
228	   * Send a user message WITH attachments (the file-upload path the real UI uses).
229	   *
230	   * The HTTP `POST /message` route is content-only — it silently drops attachments
231	   * (`sessions.ts` wires `sendMessage: (content) => manager.sendMessage(id, content)`, no third
232	   * arg). Only the WebSocket path carries `attachmentIds` (`ws/agent.ts` →
233	   * `msg.attachments.map(a => a.id)`). So to attach a file we open the same `/api/ws` socket the
234	   * `/chat` SPA uses, send one `{type:'sendMessage', content, attachments}` frame, then fall back to
235	   * the normal HTTP trace-poll to await the turn (the socket also streams the trace, but reusing the
236	   * HTTP settle-loop keeps one code path for "turn finished").
237	   *
238	   * @param {string} content
239	   * @param {Array<{id:string,kind:string,mediaType:string,url?:string,filename?:string}>} attachments
240	   *        AttachmentRefs from `pod.upload()`. The server trusts only `id` (re-reads bytes by id).
241	   */
242	  async sendWithAttachments(content, attachments, opts = {}) {
243	    const refs = attachments.map((a) => ({
244	      id: a.id,
245	      kind: a.kind,
246	      mediaType: a.mediaType,
247	      url: a.url ?? `/api/uploads/${a.id}`,
248	      ...(a.filename ? { filename: a.filename } : {}),
249	    }));
250	    await this.#ensureAlive();
251	    return this.#dispatchAndWait(
252	      () => this.#wsSend({ type: 'sendMessage', content, attachments: refs }),
253	      `${content}  [+${refs.length} attachment(s)]`,
254	      opts,
255	    );
256	  }
257	
258	  /** Open the pod's chat WebSocket, send one frame, resolve when it's flushed, then close. */
259	  #wsSend(frame) {
260	    const wsBase = this.pod.base.replace(/^http/, 'ws');
261	    const tokenQ = this.pod.token ? `&access_token=${encodeURIComponent(this.pod.token)}` : '';
262	    const url = `${wsBase}/api/ws?sessionId=${this.sessionId}${tokenQ}`;
263	    return new Promise((resolve, reject) => {
264	      const ws = new WebSocket(url); // Node ≥22 global WebSocket — zero-dep
265	      const fail = (e) => reject(e instanceof Error ? e : new Error(`ws error: ${JSON.stringify(e)}`));
266	      ws.addEventListener('open', () => {
267	        ws.send(JSON.stringify(frame));
268	        // Give the frame a beat to flush, then close; the turn is awaited over HTTP.
269	        setTimeout(() => {
270	          try {
271	            ws.close();
272	          } catch {
273	            /* ignore */
274	          }
275	          resolve();
276	        }, 750);
277	      });
278	      ws.addEventListener('error', fail);
279	    });
280	  }
281	
282	  async #dispatchAndWait(dispatch, logLine, { timeoutMs = 600_000, quietMs = 4_000, pollMs = 1_500 } = {}) {
283	    const startSeq = this.events.length;
284	    const t0 = Date.now();
285	    await dispatch();
286	    this.log('→', logLine.slice(0, 140));
287	
288	    let lastChange = Date.now();
289	    let sawWork = false;
290	    let quietSince = null;
291	    this.sessionGone = false;
292	
293	    while (Date.now() - t0 < timeoutMs) {
294	      const fresh = await this.pullEvents();
295	      if (fresh.length) {
296	        lastChange = Date.now();
297	        sawWork = true;
298	        quietSince = null;
299	      }
300	
301	      // The session vanished mid-turn (evicted past `maxSessions`, or the pod rolled/woke from
302	      // scale-to-zero under us — sessions are in-memory). We saw work, but we do NOT know the turn
303	      // FINISHED: a long build (build_specialist → deep_research → architect) can be cut off with
304	      // nothing durable written. Returning silently here reports a killed turn as a completed one —
305	      // that is how scenario 07's Act V "built" two sections and produced no space, table or page.
306	      // So flag it: `turn.interrupted` lets the caller re-send once the pod is back (see run.mjs).
307	      if (this.sessionGone) {
308	        if (sawWork) return { ...this.turn(startSeq, Date.now() - t0), interrupted: true };
309	        throw new Error(`session ${this.sessionId} disappeared before doing any work (pod restart mid-init?)`);
310	      }
311	
312	      // Drain asks (consent cards, forms) — an unanswered ask stalls the turn forever.
313	      for (const ask of await this.openAsks().catch(() => [])) {
314	        if (this.asks.some((a) => a.id === ask.id)) continue;
315	        const answer = this.onAsk ? this.onAsk(ask.descriptor, ask) : undefined;
316	        this.asks.push({ id: ask.id, descriptor: ask.descriptor, answered: answer });
317	        if (answer !== undefined) {
318	          await this.answerAsk(ask.id, answer).catch(() => {});
319	          lastChange = Date.now();
320	        }
321	      }
322	
323	      const sessions = await this.pod.req('GET', '/api/sessions').catch(() => ({ sessions: [] }));
324	      const me = (sessions.sessions ?? []).find((s) => s.sessionId === this.sessionId);
325	      const idle = me?.status === 'idle';
326	      if (me?.status === 'error') {
327	        await this.pullEvents();
328	        throw new Error(`session entered error state: ${JSON.stringify(me)}`);
329	      }
330	      // The session is no longer LISTED, though we saw work. Same hazard as `sessionGone` above and
331	      // it must be flagged the same way: "not resident any more" does NOT mean "the turn finished".
332	      // A shared local server that a sibling lane restarts (or any drop of the in-memory session)
333	      // vanishes the entry mid-flight, and a turn that had only just dispatched its delegates gets
334	      // reported as a COMPLETED turn with no results. Scenario 10 then sent the user's "yes" into a
335	      // session that had never made the offer it was agreeing to, and every downstream Act failed on
336	      // a build that never happened. Flag it — `turn.interrupted` is the caller's cue to re-send.
337	      if (sawWork && !me && this.events.length > startSeq) {
338	        return { ...this.turn(startSeq, Date.now() - t0), interrupted: true };
339	      }
340	
341	      if (sawWork && idle && Date.now() - lastChange >= quietMs) {
342	        if (quietSince === null) quietSince = Date.now();
343	        await this.pullEvents(); // final drain
344	        return this.turn(startSeq, Date.now() - t0);
345	      }
346	      await sleep(pollMs);
347	    }
348	    await this.pullEvents();
349	    const open = await this.openAsks();
350	    throw Object.assign(
351	      new Error(
352	        `turn timed out after ${timeoutMs}ms` +
353	          (open.length ? ` with ${open.length} unanswered ask(s): ${JSON.stringify(open)}` : ''),
354	      ),
355	      { turn: this.turn(startSeq, Date.now() - t0), openAsks: open },
356	    );
357	  }
358	
359	  /** A view over just the events of one turn, with the derived facts a scenario asserts on. */
360	  turn(startSeq = 0, durationMs = 0) {
361	    const evs = this.events.slice(startSeq);
362	    return {
363	      durationMs,
364	      events: evs,
365	      text: textOf(evs),
366	      /** ONLY the turn's final display — the reply the user actually reads. `text` concatenates every
367	       *  display in the slice, which on a RESUMED session can still include replayed history, so a
368	       *  check about "what it answered" must read this, never `text`. */
369	      lastText: lastTextOf(evs),
370	      yields: evs.filter((e) => e.type === 'yield').map((e) => ({ kind: e.kind, args: e.args })),
371	      delegates: evs
372	        .filter((e) => e.type === 'yield' && e.kind === 'delegate')
373	        .map((e) => delegateRef(e.args)),
374	      // `attempt` is load-bearing: the turn loop retries a typecheck/eval error up to `maxRetries`
375	      // (default 3); an error logged at attempt < 3 is RECOVERED (the loop kept going and reset the
376	      // counter on the next success), one at attempt >= 3 made the loop give up (`return 'error'`).
377	      // A scenario that must distinguish "recovered = metric" from "unrecovered = hard fail" (per the
378	      // campaign's error policy) needs this — dropping it made every recovered slip look fatal.
379	      errors: evs
380	        .filter((e) => e.type === 'eval_error' || e.type === 'typecheck_error')
381	        .map((e) => ({ type: e.type, message: e.message, statement: e.statement, attempt: e.attempt })),
382	      tokens: evs.reduce(
383	        (acc, e) =>
384	          e.type === 'llm_response'
385	            ? { in: acc.in + (e.inputTokens ?? 0), out: acc.out + (e.outputTokens ?? 0) }
386	            : acc,
387	        { in: 0, out: 0 },
388	      ),
389	      llmCalls: evs.filter((e) => e.type === 'llm_response').length,
390	      nodes: evs
391	        .filter((e) => e.type === 'node_end')
392	        .map((e) => ({ id: e.nodeId, status: e.status, ms: e.durationMs, error: e.error })),
393	    };
394	  }
395	
396	  /** Did the agent call this yield kind anywhere in the session? (e.g. 'installSpace') */
397	  didYield = (kind) => this.events.some((e) => e.type === 'yield' && e.kind === kind);
398	  /** Did it delegate to this `space/agent` (or just this space)? */
399	  didDelegate = (ref) =>
400	    this.events.some(
401	      (e) => e.type === 'yield' && e.kind === 'delegate' && delegateRef(e.args).startsWith(ref),
402	    );
403	  /** All consent cards raised this session. */
404	  consentCards = () => this.asks.filter((a) => a.descriptor?.type === 'ConsentCard');
405	
406	  /** The default `maxRetries` in the turn loop (core/src/eval/turn-loop.ts). An error logged at an
407	   *  attempt >= this made the loop give up — it was NOT recovered. */
408	  static MAX_RETRIES = 3;
409	  /** Errors the turn loop could NOT recover from (attempt reached maxRetries). Recovered slips
410	   *  (attempt < maxRetries) are a metric, not a failure — see the campaign error policy. */
411	  unrecoveredErrors = () =>
412	    this.turn(0, 0).errors.filter((e) => (e.attempt ?? 1) >= ThingSession.MAX_RETRIES);
413	
414	  /** Full session totals — for the performance table in the scenario report. */
415	  stats() {
416	    const t = this.turn(0, 0);
417	    return {
418	      events: this.events.length,
419	      llmCalls: t.llmCalls,
420	      tokens: t.tokens,
421	      errors: t.errors.length,
422	      unrecoveredErrors: this.unrecoveredErrors().length,
423	      delegates: t.delegates,
424	      yieldKinds: [...new Set(t.yields.map((y) => y.kind))],
425	    };
426	  }
427	}
428	
429	/** Human-readable delegate target from the yield args (`{space, agent, action}` or positional). */
430	function delegateRef(args) {
431	  if (Array.isArray(args)) return args.slice(0, 3).filter(Boolean).join('/');
432	  if (args && typeof args === 'object') {
433	    const { space, agent, action } = args;
434	    return [space, agent, action].filter(Boolean).join('/');
435	  }
436	  return String(args);
437	}
438	
439	/** The prose THING showed the user: display() descriptors + the final assistant text. */
440	export function textOf(events) {
441	  const out = [];
442	  for (const e of events) {
443	    if (e.type === 'display') {
444	      const d = e.descriptor;
445	      const s =
446	        typeof d === 'string'
447	          ? d
448	          : (d?.props?.text ?? d?.props?.children ?? d?.props?.content ?? JSON.stringify(d));
449	      out.push(typeof s === 'string' ? s : JSON.stringify(s));
450	    }
451	  }
452	  return out.join('\n');
453	}
454	
455	/** The LAST thing THING displayed — its final reply for this turn (see `turn().lastText`). */
456	export function lastTextOf(events) {
457	  for (let i = events.length - 1; i >= 0; i--) {
458	    const e = events[i];
459	    if (e.type !== 'display') continue;
460	    const d = e.descriptor;
461	    const s =
462	      typeof d === 'string'
463	        ? d
464	        : (d?.props?.text ?? d?.props?.children ?? d?.props?.content ?? JSON.stringify(d));
465	    const out = typeof s === 'string' ? s : JSON.stringify(s);
466	    if (out && out.trim()) return out;
467	  }
468	  return '';
469	}
