1	/**
2	 * Scenario report builder — turns a run into the "Actual results" table that gets pasted back
3	 * into the scenario's markdown file, so every run is reproducible and reviewable.
4	 *
5	 * A scenario is a list of steps; each step has an EXPECTED outcome declared up front and an
6	 * ACTUAL outcome recorded at run time. `check()` records a pass/fail against an expectation;
7	 * `note()` records an observation. Nothing throws by default — a scenario is meant to run to the
8	 * end and report every failure, not die on the first one.
9	 */
10	import { mkdirSync, writeFileSync } from 'node:fs';
11	import { dirname } from 'node:path';
12	
13	export class Report {
14	  constructor(id, title) {
15	    this.id = id;
16	    this.title = title;
17	    this.started = Date.now();
18	    this.steps = [];
19	    this.current = null;
20	    this.metrics = [];
21	    this.issues = [];
22	  }
23	
24	  /** Begin a step. `expected` is the contract this step is asserting. */
25	  step(name, expected) {
26	    this.current = { name, expected, checks: [], notes: [], started: Date.now() };
27	    this.steps.push(this.current);
28	    console.log(`\n── ${this.id} · ${name}\n   expect: ${expected}`);
29	    return this.current;
30	  }
31	
32	  check(label, pass, actual = '') {
33	    const rec = { label, pass: !!pass, actual: String(actual).slice(0, 500) };
34	    (this.current?.checks ?? (this.current = this.step('(unnamed)', '')).checks).push(rec);
35	    console.log(`   ${pass ? '✓' : '✗'} ${label}${actual ? ` — ${String(actual).slice(0, 160)}` : ''}`);
36	    return rec.pass;
37	  }
38	
39	  note(text) {
40	    this.current?.notes.push(String(text));
41	    console.log(`   · ${text}`);
42	  }
43	
44	  /** A row for the performance table (turn timings, token burn, event counts). */
45	  metric(name, value, unit = '') {
46	    this.metrics.push({ name, value, unit });
47	    console.log(`   ▸ ${name}: ${value}${unit}`);
48	  }
49	
50	  /** A bug found during the run. `fix` is filled in once the subagent has fixed it. */
51	  issue(title, detail, { severity = 'bug', fix = null } = {}) {
52	    this.issues.push({ title, detail: String(detail).slice(0, 2000), severity, fix });
53	    console.log(`   ⚠ ISSUE [${severity}] ${title}`);
54	  }
55	
56	  get passed() {
57	    return this.steps.every((s) => s.checks.every((c) => c.pass));
58	  }
59	
60	  /**
61	   * Did the step CURRENTLY being recorded pass?
62	   *
63	   * `passed` is the whole report; an Act's checkpoint must record the ACT. Writing
64	   * `cp.acts.VIII = { passed: report.passed }` after a batch where Act VII failed marked Act VIII
65	   * failed too — all three of its checks were green. A checkpoint that lies about which Act broke
66	   * is worse than no checkpoint: the next run re-debugs the wrong Act.
67	   */
68	  get stepPassed() {
69	    return (this.current?.checks ?? []).every((c) => c.pass);
70	  }
71	
72	  summary() {
73	    const all = this.steps.flatMap((s) => s.checks);
74	    return { total: all.length, passed: all.filter((c) => c.pass).length, issues: this.issues.length };
75	  }
76	
77	  /** Render the "Actual results" markdown that gets appended to the scenario doc. */
78	  markdown() {
79	    const s = this.summary();
80	    const mins = ((Date.now() - this.started) / 60_000).toFixed(1);
81	    const L = [
82	      `## Actual results — run ${new Date(this.started).toISOString()}`,
83	      ``,
84	      `**Verdict: ${this.passed ? '✅ PASS' : '❌ FAIL'}** · ${s.passed}/${s.total} checks · ` +
85	        `${s.issues} issue(s) found · ${mins} min wall clock`,
86	      ``,
87	    ];
88	    for (const st of this.steps) {
