517	  report.check('EDGE: unknown path → 404', unknown.status === 404, `status ${unknown.status}`);
518	  const malformed = await signedInbound(pod, 'demo', { not_a_message: true }, DEMO_SECRET);
519	  report.check('EDGE: malformed body (no message) → 200 {events:0}', malformed.status === 200 && (malformed.body?.events ?? 0) === 0, `status ${malformed.status}: ${JSON.stringify(malformed.body).slice(0, 100)}`);
520	  cp.acts.VII = { passed: report.stepPassed };
