534	  const t = acc(await timed('Act VIII — a normal turn right after the storm', () => thing.send('quick one — how many wholesale orders are still unpaid right now?', { timeoutMs: TURN })));
535	  report.check('an ordinary chat turn right after the storm still completes (event loop not starved)', (t.llmCalls ?? 0) >= 1 && t.errors.length === 0, `${t.llmCalls} llm calls, ${t.errors.length} errors`);
536	  cp.acts.VIII = { passed: report.stepPassed };
