657	}
658	
659	// ═══ ACT XIV — A2: it actually renders (app API layer; browser done separately) ═════
660	if (ACTS.includes(14)) {
661	  report.step(
662	    'Act XIV — the served app renders real data through its OWN api layer',
663	    'the app\'s own API routes return 200 with real shape (not just the raw data API); the served root is 200 HTML with fixture-derived values. (Chrome render + console/network asserted separately by the agent via chrome-devtools.)',
664	  );
665	  await assertAppApi(report, pod, PROJECT);
666	  const page = await pod.appPage(PROJECT).catch((e) => ({ status: 0, body: String(e) }));
667	  report.check('served app root → 200 HTML', page.status === 200 && String(page.body).includes('<!doctype'), `status ${page.status}`);
668	  const rows = await allRows(pod, PROJECT);
669	  const flat = JSON.stringify(rows);
670	  const derived = ['Keramikos', 'Sibelco', 'WHL-0007', 'tenmoku', 'Cobalt'].filter((v) => new RegExp(normAlnum(v), 'i').test(normAlnum(flat)));
671	  report.check('the app data contains ≥3 real fixture-derived values (non-empty shop)', derived.length >= 3, derived.join(', '));
672	  report.note('Browser render (DOM values on screen, both chat surfaces present, zero console errors / failed fetches) is verified by the agent driving chrome-devtools — see the report narrative + screenshot path.');
673	  cp.acts.XIV = { passed: report.stepPassed };
674	  saveCheckpoint(cp);
675	}
676	
677	// ═══ verdict ════════════════════════════════════════════════════════════════════════
678	const stats = thing.stats();
679	report.step('Whole-session invariants (Edges)', 'zero UNRECOVERED eval/typecheck errors on THING\'s own turns; the SSRF echo host never reached; routing not degraded');
680	report.check('zero eval/typecheck errors across the THING session (hard fail)', stats.errors === 0, `${stats.errors} errors: ${JSON.stringify(stats).slice(0, 200)}`);
681	report.metric('wall clock', ((now() - t0) / 60_000).toFixed(1), ' min');
682	report.metric('total tokens (in/out)', `${metrics.tokens.in} / ${metrics.tokens.out}`);
